INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05580', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於聯合國消除對婦女一切形式歧視公約、兒童權利公約、身心障礙者權利公約三個國際公約，臺灣近 年均有相關立法措施，下列敘述何者正確？', '["三個國內公約施行法通過時間，以身心障礙者權利公約施行法最早、兒童權利公約施行法次之、消除 對婦女一切形式歧視公約施行法最晚", "三個國際公約在臺灣均已通過具有國內法律效力之施行法", "三個公約施行法均規定國家應建立相關報告制度，每 5 年需提出國家報告，邀請相關專家學者及民間 團體代表審閱，政府應依審閱意見檢討，研擬後續施政", "三個公約施行法均明定在行政院層級，為推動公約相關工作，應設立權益推動小組，定期召開會議， 小組組成成員任一性別不得少於二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05581', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '兒童及少年福利與權益保障法第33條之2規定，某些場所應規劃設置適合六歲以下兒童及其照顧者共同 使用之親子廁所盥洗室，並附設兒童安全座椅、尿布臺等相關設備，下列何者不在法令規定內？', '["提供民眾申辦業務或服務之場所總樓地板面積五千平方公尺以上之政府機關（構）、公營事業、鐵路 車站、航空站及捷運交會轉乘站", "營業場所總樓地板面積一萬平方公尺以上之百貨公司及零售式量販店", "營業場所總樓地板面積五千平方公尺以上之餐廳", "設有兒科病房之區域級以上醫院、觀光遊樂業之園區"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05582', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關就業保險法之敘述，下列何者錯誤？', '["若被保險人領有社政主管機關核發之身心障礙證明者，可延長失業給付請領期間至九個月", "父母同為被保險人者，應分別請領育嬰留職停薪津貼，不得同時為之", "申請失業給付者，須為非自願離職，且辦理退保當日前三年內，保險年資合計滿一年以上，有工作能 力及繼續工作意願，向公立就業服務機構辦理求職登記", "申請人對公立就業服務機構推介之工作，可以專長不符為由拒絕，仍得請領失業給付"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05583', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '自立脫貧是社會救助的核心精神之一，為落實積極性福利的價值，下列何者不是我國社會救助協助低收 入戶及中低收入戶中有工作能力者相關促進就業的服務措施？', '["求職交通補助", "求職或職業訓練期間之臨時托育及日間照顧津貼", "失業救助津貼", "以工代賑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05584', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列關於現代福利國家發展的敘述，何者錯誤？', '["福利國家的誕生可回溯自1884年德國建立意外保險制度開始", "福利國家的起源受到當時工業化、都市化、人口成長、社會民主及傳統福利供給（provision）如家庭網 絡、慈善組織等功能式微的影響", "福利國家的擴張體現在涵蓋人口、服務範圍與風險項目及給付水準增加", "福利國家在1980年的轉變，與經濟成長停滯、人口老化以及新右派政治勢力興起有關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05585', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '身心障礙者權益保障法中有關障礙鑑定及需求評估的敘述，下列何者正確？', '["身心障礙者對障礙鑑定及需求評估有異議者，應於收到通知書之次日起六十日內，以書面向主管機關 提出申請重新鑑定及需求評估，並以三次為限", "依身心障礙者權益保障法申請重新鑑定及需求評估，應全額負擔相關作業費用；其異議成立者，應退 還之", "身心障礙者障礙情況改變時，應自行向主管機關申請重新鑑定及需求評估；直轄市、縣（市）主管機 關發現身心障礙者障礙情況改變時，得以書面通知其於六十日內辦理重新鑑定與需求評估", "身心障礙證明有效期限最長為三年，身心障礙者應於效期屆滿前六十日內向戶籍所在地之主管機關申 請辦理重新鑑定及需求評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05586', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國105年11月行政院核定實施「兒童與少年未來教育及發展帳戶」，凡符合資格之兒童及少年，於帳 戶所有人年滿18歲前，每人每年最高儲蓄1萬5,000元；政府相對提撥同額款項。下列有關此方案的身 分變動與提領機制之敘述，何者正確？', '["適用對象為列冊之低收入戶與中低收入戶兒童及少年，排除長期安置之兒童及少年", "開戶人如因死亡、罹患嚴重疾病或身心障礙等特殊狀況，始得於18歲前提早結清帳戶領回存款，且帳 戶結清後即不得再重新開立本帳戶", "兒童及少年於年滿18歲前，如中途自願退出，由地方政府社工人員評估結合資源，或加強教育提高存 款誘因，保留三年緩衝期，屆期可領取自存款及利息", "經地方政府社工輔導，至年滿18歲其自存款仍未達3萬元者，僅能領回自存款，不包含利息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05587', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '性別工作平等法中，關於促進工作平等措施，下列敘述何者錯誤？', '["受僱者於其家庭成員預防接種、發生嚴重之疾病或其他重大事故須親自照顧時，得請家庭照顧假", "請家庭照顧假日數併入事假計算，全年以7日為限", "家庭照顧假薪資之計算，依各該事假規定辦理", "受僱者之配偶未就業者，亦適用此規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05588', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '就我國社會安全制度實施的不同類型做比較，生育給付是屬於何種社會福利給付型式？', '["社會救助", "社會津貼", "社會保險", "稅制福利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05589', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '身心障礙者權益保障法中關於身心障礙者支持服務與經濟安全的敘述，下列何者正確？', '["主管機關對轄區內之身心障礙者，應依需求評估結果，提供某些法定經費補助，有設籍時間至少半年 以上之限制", "身心障礙者醫療復健所需之醫療費用及醫療輔具，尚未納入全民健康保險給付範圍者，主管機關應依 需求評估結果補助", "身心障礙者或其扶養者依本法規定所得之各項補助，應納所得稅", "主管機關辦理復康巴士服務，應有設籍之限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "4a10b3adab34", "answer_pdf_sha1": "353a361386a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
